code = """import json

# Get citations data
citations_data = locals()['var_functions.query_db:22']

# I need to find papers published in 2016, not just cited in 2016
# Let me check if any of these papers have 2016 in their title or if I can infer publication year

pa_citations_2016 = [c for c in citations_data if c['citation_year'] == '2016']

print('Physical activity papers with citations in 2016:')
for c in pa_citations_2016:
    print(c['title'] + ' - ' + c['citation_count'] + ' citations in 2016')

# Let me also check for any papers that might have been published in 2016
# by looking for 2016 in the paper documents

file_path = locals()['var_functions.query_db:20']

papers_2016 = []
try:
    with open(file_path, 'r') as f:
        paper_docs = json.load(f)
    
    for doc in paper_docs:
        text = doc['text']
        # Look for papers with 2016 mentioned (likely publication year)
        if '2016' in text:
            filename = doc['filename']
            title = filename.replace('.txt', '')
            # Check if physical activity related
            text_lower = text.lower()
            pa_keywords = ['physical activity', 'physical activities', 'fitness', 'exercise', 'workout', 'running']
            if any(keyword in text_lower for keyword in pa_keywords):
                papers_2016.append(title)
except Exception as e:
    print('Error reading paper docs: ' + str(e))

print('\nPhysical activity papers mentioning 2016:')
for p in papers_2016:
    print('  - ' + p)

result = {
    'papers_2016_pa_titles': papers_2016,
    'citations_2016': pa_citations_2016
}

print('__RESULT__:')
print(json.dumps(result, indent=2))"""

